const OPENAI_API_KEY = "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";

// 🔥 BLOG GENERATION (REAL AI)
export async function generateBlog(title) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "Write a detailed blog article (500-800 words) with headings, paragraphs, and simple readable English.",
          },
          {
            role: "user",
            content: title,
          },
        ],
        temperature: 0.7,
      }),
    });

    const data = await res.json();

    if (!res.ok) {
      console.error(data);
      throw new Error("API failed");
    }

    return data.choices?.[0]?.message?.content;
  } catch (err) {
    console.error(err);

    // fallback (no one-line anymore)
    return `
# ${title}

${title} is an important topic in today's world. It plays a significant role in shaping modern understanding and innovation.

In this article, we explore how ${title.toLowerCase()} impacts different areas, including technology, society, and personal development.

Understanding this concept helps individuals make better decisions and stay updated in a fast-changing world.

Overall, ${title.toLowerCase()} continues to grow in importance and influence future trends globally.
`;
  }
}

// 🔥 TAGS
export async function generateTags(title, content) {
  const words = (title + content)
    .toLowerCase()
    .split(/\W+/)
    .filter((w) => w.length > 4);

  return [...new Set(words)].slice(0, 5);
}

// 🔥 ANALYSIS
export async function analyzeWriting(title, content) {
  return {
    score: 8,
    tone: "Professional",
    readability: "Medium",
    strengths: ["Clear topic", "Good flow"],
    improvements: ["Add examples"],
    rewrittenIntro: `This article explores ${title} in a clear and simple way.`,
  };
}

// 🔥 SUMMARY
export async function generateSummary(title, content) {
  return content.slice(0, 150) + "...";
}

// 🔥 SENTIMENT
export async function analyzeCommentSentiment(text) {
  return {
    sentiment: "Positive",
    score: 0.9,
  };
}

// 🔥 RECOMMENDATIONS
export async function getRecommendations(history, posts) {
  return posts?.slice(0, 3) || [];
}
